<template>
    <div class="water-flow-dashboard">
        <!-- 背景 -->
        <div class="background"></div>

        <!-- 头部 -->
        <div class="header">
            <img src="@/assets/供水流程驾驶舱/头部.png" alt="头部" class="header-img" />
            <div class="header-time">{{ currentTime }}</div>
            <div class="header-actions">
                <div class="action-btn" @click="goBack">
                    <img src="@/assets/供水流程驾驶舱/返回门户.png" alt="返回门户" />
                    <span>返回门户</span>
                </div>
                <div class="action-btn" @click="goAdmin">
                    <img src="@/assets/供水流程驾驶舱/进入后台.png" alt="进入后台" />
                    <span>进入后台</span>
                </div>
            </div>
        </div>

        <!-- 左侧 - 水源 -->
        <div class="left-section">
            <div class="section-title">水源</div>
            
            <!-- 水源取水井可视化管道 -->
            <div class="water-wells-visual">
                <div class="well-column" v-for="(well, index) in waterWells" :key="index">
                    <div class="well-pipe-top"></div>
                    <div class="well-pipe-vertical"></div>
                    <div class="well-pipe-horizontal"></div>
                    <div class="well-label">{{ well.name }}</div>
                </div>
            </div>

            <!-- 取水井数据面板 -->
            <div class="well-data-panel">
                <img src="@/assets/供水流程驾驶舱/边框2.png" alt="边框" class="panel-border" />
                <div class="panel-content">
                    <div class="data-row" v-for="(item, index) in wellData" :key="index">
                        <span class="data-label">{{ item.label }}</span>
                        <span class="data-value">{{ item.value }}</span>
                        <span class="data-unit">{{ item.unit }}</span>
                        <span class="data-pressure">{{ item.pressure }}</span>
                    </div>
                </div>
            </div>
        </div>

        <!-- 中央 - 水厂流程 -->
        <div class="center-section">
            <div class="factory-title">水厂</div>
            
            <!-- 水厂数据区域 -->
            <div class="factory-data-area">
                <!-- 上排数据 -->
                <div class="data-boxes-top">
                    <div class="data-box" v-for="item in topData" :key="item.id">
                        <div class="box-label">{{ item.label }}</div>
                        <div class="box-value">{{ item.value }}</div>
                    </div>
                </div>
                
                <!-- 下排数据 -->
                <div class="data-boxes-bottom">
                    <div class="data-box" v-for="item in bottomData" :key="item.id">
                        <div class="box-label">{{ item.label }}</div>
                        <div class="box-value">{{ item.value }}</div>
                    </div>
                </div>
            </div>

            <!-- 管道流程图 SVG -->
            <div class="pipeline-container">
                <svg class="pipeline-svg" viewBox="0 0 1200 500" xmlns="http://www.w3.org/2000/svg">
                    <defs>
                        <!-- 管道虚线图案 -->
                        <pattern id="pipePattern" x="0" y="0" width="20" height="20" patternUnits="userSpaceOnUse">
                            <rect x="0" y="0" width="10" height="20" fill="#00d4ff"/>
                            <rect x="10" y="0" width="10" height="20" fill="#0088aa"/>
                        </pattern>
                        
                        <!-- 流动动画渐变 -->
                        <linearGradient id="flowGradient">
                            <stop offset="0%" style="stop-color:#00d4ff;stop-opacity:0.3" />
                            <stop offset="50%" style="stop-color:#00d4ff;stop-opacity:1" />
                            <stop offset="100%" style="stop-color:#00d4ff;stop-opacity:0.3" />
                        </linearGradient>
                        
                        <!-- 发光滤镜 -->
                        <filter id="glow">
                            <feGaussianBlur stdDeviation="2" result="coloredBlur"/>
                            <feMerge>
                                <feMergeNode in="coloredBlur"/>
                                <feMergeNode in="SourceGraphic"/>
                            </feMerge>
                        </filter>
                    </defs>

                    <!-- ========== 左侧区域：水源井 ========== -->
                    <g class="water-source-section">
                        <!-- 三个水源井 -->
                        <g class="well" transform="translate(50, 50)">
                            <rect x="-5" y="0" width="10" height="100" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                            <circle cx="0" cy="110" r="8" fill="#00d4ff" filter="url(#glow)">
                                <animate attributeName="r" values="8;10;8" dur="2s" repeatCount="indefinite"/>
                            </circle>
                        </g>
                        <g class="well" transform="translate(100, 50)">
                            <rect x="-5" y="0" width="10" height="100" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                            <circle cx="0" cy="110" r="8" fill="#00d4ff" filter="url(#glow)">
                                <animate attributeName="r" values="8;10;8" dur="2s" repeatCount="indefinite"/>
                            </circle>
                        </g>
                        <g class="well" transform="translate(150, 50)">
                            <rect x="-5" y="0" width="10" height="100" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                            <circle cx="0" cy="110" r="8" fill="#00d4ff" filter="url(#glow)">
                                <animate attributeName="r" values="8;10;8" dur="2s" repeatCount="indefinite"/>
                            </circle>
                        </g>
                        
                        <!-- 汇集管道 -->
                        <path d="M 50,160 L 50,200 L 150,200 L 150,160" fill="none" stroke="#00d4ff" stroke-width="10" stroke-linecap="round"/>
                        <rect x="45" y="155" width="110" height="10" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                        
                        <!-- 汇集后的下行管道 -->
                        <rect x="95" y="200" width="10" height="120" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                        
                        <!-- 水池 -->
                        <g transform="translate(100, 340)">
                            <rect x="-35" y="-20" width="70" height="40" fill="rgba(0, 40, 80, 0.8)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                            <path d="M -25,-5 Q -15,-10 -5,-5 T 15,-5" fill="none" stroke="#00d4ff" stroke-width="2">
                                <animate attributeName="d" values="M -25,-5 Q -15,-10 -5,-5 T 15,-5;M -25,-5 Q -15,0 -5,-5 T 15,-5;M -25,-5 Q -15,-10 -5,-5 T 15,-5" dur="2s" repeatCount="indefinite"/>
                            </path>
                        </g>
                        
                        <!-- 输出管道 -->
                        <path d="M 100,360 L 100,400 L 250,400" fill="none" stroke="#00d4ff" stroke-width="10" stroke-linecap="round"/>
                        <rect x="95" y="355" width="10" height="50" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                        <rect x="100" y="395" width="155" height="10" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                    </g>

