                        <path d="M 250,180 L 900,180" fill="none" stroke="#00d4ff" stroke-width="10" stroke-linecap="round"/>
                        <rect x="250" y="175" width="650" height="10" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                        
