                            <line x1="-20" y1="0" x2="20" y2="0" stroke="#00d4ff" stroke-width="1"/>
                            <line x1="-20" y1="10" x2="20" y2="10" stroke="#00d4ff" stroke-width="1"/>
                            <!-- 竖直连接管道 -->
                            <rect x="-5" y="20" width="10" height="45" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                        </g>
                    </g>

                    <!-- 下层管道 -->
                    <g class="bottom-pipeline">
