                            <line x1="-20" y1="0" x2="20" y2="0" stroke="#00d4ff" stroke-width="1"/>
                            <line x1="-20" y1="10" x2="20" y2="10" stroke="#00d4ff" stroke-width="1"/>
                            <!-- 竖直连接管道 -->
                            <rect x="-5" y="-60" width="10" height="40" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                        </g>
                    </g>

                    <!-- 连接进水到上下管道 -->
                    <rect x="245" y="185" width="10" height="130" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                    <circle cx="250" cy="250" r="15" fill="#003d5c" stroke="#00d4ff" stroke-width="2"/>

                    <!-- ========== 右侧区域：供水系统 ========== -->
                    <g class="supply-section">
                        <!-- 上层过滤池 -->
                        <g transform="translate(950, 120)">
                            <rect x="-60" y="-30" width="120" height="60" fill="rgba(0, 40, 80, 0.8)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                            <circle cx="-30" cy="0" r="12" fill="#00d4ff" opacity="0.5"/>
                            <circle cx="0" cy="0" r="12" fill="#00d4ff" opacity="0.5"/>
                            <circle cx="30" cy="0" r="12" fill="#00d4ff" opacity="0.5"/>
                            <!-- 连接管道 -->
                            <rect x="-5" y="30" width="10" height="35" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                        </g>
                        
                        <!-- 中层 -->
                        <g class="middle-layer">
                            <!-- 左侧水平管道 -->
                            <rect x="945" y="175" width="150" height="10" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                            
                            <!-- 阀门图标 -->
                            <g transform="translate(1010, 180)">
                                <rect x="-8" y="-8" width="16" height="16" fill="#003d5c" stroke="#00d4ff" stroke-width="2" rx="2"/>
                                <line x1="-4" y1="0" x2="4" y2="0" stroke="#00d4ff" stroke-width="2"/>
                            </g>
                            
                            <!-- 水泵 -->
                            <g transform="translate(760, 280)">
                                <path d="M -15,-10 L -15,10 L 0,0 Z" fill="#00d4ff"/>
                                <circle cx="0" cy="0" r="15" fill="none" stroke="#00d4ff" stroke-width="2"/>
                            </g>
                            
                            <g transform="translate(850, 330)">
                                <circle cx="0" cy="0" r="20" fill="#003d5c" stroke="#00d4ff" stroke-width="2"/>
                                <circle cx="0" cy="0" r="12" fill="#00d4ff" opacity="0.5"/>
                            </g>
                            
                            <g transform="translate(950, 380)">
                                <circle cx="0" cy="0" r="20" fill="#003d5c" stroke="#00d4ff" stroke-width="2"/>
                                <circle cx="0" cy="0" r="12" fill="#00d4ff" opacity="0.5"/>
                            </g>
                            
                            <g transform="translate(1050, 430)">
                                <circle cx="0" cy="0" r="20" fill="#003d5c" stroke="#00d4ff" stroke-width="2"/>
                                <circle cx="0" cy="0" r="12" fill="#00d4ff" opacity="0.5"/>
                            </g>
                            
                            <!-- 管道连接 -->
                            <path d="M 760,295 L 760,320 L 850,320 L 850,330" fill="none" stroke="#00d4ff" stroke-width="10" stroke-linecap="round"/>
                            <rect x="755" y="290" width="10" height="35" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                            <rect x="760" y="315" width="95" height="10" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                            
                            <path d="M 850,350 L 850,370 L 950,370 L 950,380" fill="none" stroke="#00d4ff" stroke-width="10" stroke-linecap="round"/>
                            <rect x="845" y="345" width="10" height="30" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                            <rect x="850" y="365" width="105" height="10" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                            
                            <path d="M 950,400 L 950,420 L 1050,420 L 1050,430" fill="none" stroke="#00d4ff" stroke-width="10" stroke-linecap="round"/>
                            <rect x="945" y="395" width="10" height="30" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                            <rect x="950" y="415" width="105" height="10" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                            
                            <!-- 阀门 -->
                            <g transform="translate(820, 320)">
                                <rect x="-6" y="-6" width="12" height="12" fill="#003d5c" stroke="#00d4ff" stroke-width="2" rx="2"/>
                            </g>
                            <g transform="translate(920, 370)">
                                <rect x="-6" y="-6" width="12" height="12" fill="#003d5c" stroke="#00d4ff" stroke-width="2" rx="2"/>
                            </g>
                            <g transform="translate(1020, 420)">
                                <rect x="-6" y="-6" width="12" height="12" fill="#003d5c" stroke="#00d4ff" stroke-width="2" rx="2"/>
                            </g>
                        </g>
                        
                        <!-- 下层过滤池 -->
                        <g transform="translate(950, 380)">
                            <rect x="-60" y="-30" width="120" height="60" fill="rgba(0, 40, 80, 0.8)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                            <circle cx="-30" cy="0" r="12" fill="#00d4ff" opacity="0.5"/>
                            <circle cx="0" cy="0" r="12" fill="#00d4ff" opacity="0.5"/>
                            <circle cx="30" cy="0" r="12" fill="#00d4ff" opacity="0.5"/>
                            <!-- 连接管道 -->
                            <rect x="-5" y="-65" width="10" height="35" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                        </g>
                        
                        <!-- 汇合管道 -->
                        <rect x="945" y="165" width="10" height="150" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                        
                        <!-- 右侧输出 -->
                        <rect x="1090" y="175" width="60" height="10" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                    </g>

                    <!-- 连接中央到右侧 -->
                    <rect x="895" y="175" width="55" height="10" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                    <rect x="895" y="315" width="55" height="10" fill="url(#pipePattern)" stroke="#00d4ff" stroke-width="2" rx="5"/>
                </svg>
            </div>

            <!-- 视频监控 -->
            <div class="video-section">
                <div class="video-box">
                    <img src="@/assets/供水流程驾驶舱/视频边框.png" alt="边框" class="video-frame" />
                    <div class="video-screen">
                        <div class="video-controls">
                            <img src="@/assets/供水流程驾驶舱/播放.png" alt="播放" class="control-icon" />
                            <img src="@/assets/供水流程驾驶舱/音量.png" alt="音量" class="control-icon" />
                            <img src="@/assets/供水流程驾驶舱/全屏.png" alt="全屏" class="control-icon" />
                            <img src="@/assets/供水流程驾驶舱/更多.png" alt="更多" class="control-icon" />
                        </div>
                    </div>
                    <div class="video-title">1#监控间</div>
                </div>
                <div class="video-box">
                    <img src="@/assets/供水流程驾驶舱/视频边框.png" alt="边框" class="video-frame" />
                    <div class="video-screen">
                        <div class="video-controls">
                            <img src="@/assets/供水流程驾驶舱/播放.png" alt="播放" class="control-icon" />
                            <img src="@/assets/供水流程驾驶舱/音量.png" alt="音量" class="control-icon" />
                            <img src="@/assets/供水流程驾驶舱/全屏.png" alt="全屏" class="control-icon" />
                            <img src="@/assets/供水流程驾驶舱/更多.png" alt="更多" class="control-icon" />
