<script>
export default {
  name: 'WaterFlowDashboard',
  data() {
    return {
      currentTime: '',
      waterWells: [
        { name: '1#水源井' },
        { name: '2#水源井' },
        { name: '3#水源井' }
      ],
      wellData: [
        { label: '1#水源井', value: '49', unit: 'm³/h', pressure: '0.3 Mpa' },
        { label: '2#水源井', value: '48', unit: 'm³/h', pressure: '0.3 Mpa' },
        // { label: '3#水源井', value: '49', unit: 'm³/s', pressure: '0.15 Mpa' }
      ],
      topData: [
        { id: 1, label: '1#提升泵出口', value: '2.13 m' },
        { id: 2, label: '1#提升泵出口', value: '2.13 m' },
        { id: 3, label: '1#提升泵出口', value: '2.57 m' }
      ],
      bottomData: [
        { id: 1, label: '2#提升泵出口', value: '2.4 m' },
        { id: 2, label: '2#提升泵出口', value: '2.4 m' },
        { id: 3, label: '2#提升泵出口', value: '2.55 m' }
      ],
      endPumps: [
        { name: '1#用水泵' },
        { name: '2#用水泵' },
        { name: '3#用水泵' }
      ]
    }
  },
  mounted() {
    this.updateTime()
    setInterval(this.updateTime, 1000)
  },
  methods: {
    updateTime() {
      const now = new Date()
      const year = now.getFullYear()
      const month = String(now.getMonth() + 1).padStart(2, '0')
      const day = String(now.getDate()).padStart(2, '0')
      const hours = String(now.getHours()).padStart(2, '0')
      const minutes = String(now.getMinutes()).padStart(2, '0')
      const seconds = String(now.getSeconds()).padStart(2, '0')
